    public static AkeTijdperk getTijdperk(LocalDateInterval rekenPeriode) {
        if (rekenPeriode.getStart().isBefore(RszConstants.START_DMFAPPL) && rekenPeriode.getEnd().isBefore(RszConstants.START_DMFAPPL)) {
            return AkeTijdperk.RSZPPO;
        } else if ((rekenPeriode.getStart().compareTo(RszConstants.START_DMFAPPL) >= 0)
                && rekenPeriode.getEnd().compareTo(RszConstants.START_DMFAPPL) >= 0) {
            return AkeTijdperk.DMFAPPL;
        } else {
            throw new MessageException("de rekenperiode loopt over verschillende tijdperken");
        }
    }

    public static AkeTijdperk getTijdperk(RekenTijd rekenTijd) {
        return getTijdperk(rekenTijd.rekenPeriode);
    }

    public static AkeTijdperk getTijdperk(LocalDate datum) {
        return getTijdperk(new Day(datum));
    }

    public static boolean isVastbenoemd(SleutelGegevens gegevens, RekenTijd rekenTijd) {
        boolean vastbenoemd;
        if (getTijdperk(rekenTijd) == AkeTijdperk.RSZPPO) {
            vastbenoemd = IS_VASTBENOEMD_RSZPPO_SET.contains(gegevens.getCategorie());
        } else {
            CategorieKengetalStatuutPensioenstelsel categorieKengetalStatuutPensioenstelsel =
                    CategorieKengetalStatuutPensioenstelselFactory.create(rekenTijd, gegevens.getWerkgeversCategorie(), gegevens.getWerknemersKengetal(),
                            gegevens.getStatuutDmfappl(), gegevens.getPensioenStelsel());
            vastbenoemd = categorieKengetalStatuutPensioenstelsel.isVastbenoemd();
        }
        return vastbenoemd;
    }

    public static boolean isVastbenoemd(Opper opper, RekenTijd rekenTijd) {
        return isVastbenoemd(new SleutelGegevensSingleOpper(opper), rekenTijd);
    }

    public static boolean listContains(List<DmfapplBasisBijdrage> lijst, DmfapplWnkengetal werknemersKengetalBijdrage) {
        DmfapplBasisBijdrage gezocht = new DmfapplBasisBijdragePO();
        gezocht.setWerknemersKengetalBijdrage(werknemersKengetalBijdrage);
        lijst.sort(DmfapplBasisBijdrageComparator.DEFAULT);
        int index = Collections.binarySearch(lijst, gezocht, DmfapplBasisBijdrageComparator.DEFAULT);
        return index >= 0;
    }

