    public static <T extends ActualTemporalSlice> T getLaatsteGegevens(Collection<T> actualSlices) {
        return actualSlices.stream().max(Comparator.comparing(T::getActualTo)).orElse(null);
    }

    public static <T extends ActualTemporalSlice> T getEersteGegevens(Collection<T> actualSlices) {
        return actualSlices.stream().min(Comparator.comparing(T::getActualTo)).orElse(null);
    }

    public static <T extends ActualTemporalSlice> T getGegevensOpDatum(Collection<T> actualSlices, LocalDate datum) {
        return actualSlices.stream().filter(matchActualDatum(datum)).findAny().orElse(null);
    }

    public static Predicate<ActualTemporalSlice> matchActualDatum(LocalDate datum) {
        return o -> o.getActualInterval().contains(datum);
    }

    public static boolean isAfwezigheidscodeZonderDispo(int afwezigheidscode, RekenTijd rekenTijd) {
        boolean codeZonderDispo;
        if (getTijdperk(rekenTijd) == AkeTijdperk.RSZPPO) {
            codeZonderDispo = afwezigheidscode == RszppoPrestatiekode.PK170.getCode() || afwezigheidscode == RszppoPrestatiekode.PK171.getCode()
                    || afwezigheidscode == RszppoPrestatiekode.PK180.getCode();
        } else {
            codeZonderDispo = afwezigheidscode == RszppoPrestatiekode.PK180.getCode();
        }
        return codeZonderDispo;
    }

