    public static boolean isVerbodenLoonCodeVoorHoedanigheid(Hoedanigheid hoedanigheid, AardKodeExtensie loonCode) {
        return loonCode.getTijdperk() == 2 && loonCode.getAard() == 3 && loonCode.getCode() == 1021 && loonCode.getExtensie() == 14
                && hoedanigheid != Hoedanigheid.COMMISSIELEDEN && hoedanigheid != Hoedanigheid.RAADSLEDEN;
    }

