    public static Money getSomProperty(ContextKey key, Collection<LoonElement> loonElementen) {
        Money totaal = Money.ZERO;
        if (loonElementen != null) {
            totaal = loonElementen.stream().map(mapToMoney(key)).reduce(Money.ZERO, Money::add);
        }
        return totaal;
    }

    public static Money getSomProperty(ContextKey key, Collection<LoonElement> loonElementen, LoonElementChecker checker) {
        Money totaal = Money.ZERO;
        if (loonElementen != null) {
            totaal = loonElementen.stream().filter(checker::check).map(mapToMoney(key)).reduce(Money.ZERO, Money::add);
        }
        return totaal;
    }

    private static Predicate<? super Identifiable> matchById(Integer id) {
        return o -> o.getId().equals(id);
    }

    private static Function<? super LoonElement, Money> mapToMoney(ContextKey key) {
        return a -> a.getPropertyMoney(key);
    }

