    public static MoneyKey bedragTypeToMoneyKey(RekenBedragType bedragType, LnedefRegBv regimeBv, LocalDate rekenDatum) {
        MoneyKey moneyKey = BEDRAG_TYPE_TO_MONEYKEY.get(bedragType);
        if (moneyKey instanceof RekenBvKey) {
            moneyKey = BvTools.bedragTypeToRekenBvKey(bedragType, regimeBv, rekenDatum);
        } else if (bedragType == RekenBedragType.PATRONALE_BIJDRAGE_VOERTUIG) {
            if (regimeBv != LnedefRegBv.VD_BV_10_MOB_VERG_INLV_WAGEN) {
                moneyKey = RekenPatronaalRszKey.PATRONALE_BIJDRAGE_VOERTUIG_KEY;
            } else {
                moneyKey = RekenPatronaalRszKey.PATRONALE_BIJDRAGE_VOERTUIG_2_KEY;
            }
        }
        return moneyKey;
    }

    public static MoneyKey bedragTypeToMoneyKey(RekenBedragType bedragType) {
        MoneyKey moneyKey = BEDRAG_TYPE_TO_MONEYKEY.get(bedragType);
        if (moneyKey instanceof RekenBvKey) {
            throw new MessageException("Deze methode kan niet gebruikt worden met een RekenBvKey");
        }
        return moneyKey;
    }

