    public static boolean heeftOpdrachtHoedanigheid(Collection<Opdracht> opdrachten, Set<Hoedanigheid> hoedanigheden) {
        boolean heeftOpdrachtHoedanigheid = false;
        for (Opdracht opdracht : opdrachten) {
            if (hoedanigheden.contains(opdracht.getHoedanigheid())) {
                heeftOpdrachtHoedanigheid = true;
                break;
            }
        }
        return heeftOpdrachtHoedanigheid;
    }

