        }
    }

    public static void replaceKey(LoonElement element, ContextKey replacee, ContextKey replacer) {
        Object checkForConfict = element.getProperty(replacer);
        Object transfer = element.getProperty(replacee);
        if (checkForConfict != null && transfer != null) {
            throw new MessageException("Je kan een contextKey niet vervangen door een die al gebruikt word");
        }
        if (transfer != null) {
            element.getProperties().remove(replacee);
            element.putProperty(replacer, transfer);
        }
    }

    public static void replaceKeyAndAdd(Collection<LoonElement> loonElementen, ContextKey replacee, ContextKey replacer) {
        for (LoonElement element : loonElementen) {
            replaceKeyAndAdd(element, replacee, replacer);
        }
    }

    public static void replaceKeyAndAdd(LoonElement element, ContextKey replacee, ContextKey replacer) {
        Object checkForConfict = element.getProperty(replacer);
        Object transfer = element.getProperty(replacee);
        if (transfer != null && !((checkForConfict instanceof Money || checkForConfict == null) && transfer instanceof Money)) {
            throw new MessageException("replaceKeyAndAdd is enkel toepasbaar op waarden van type Money ");
        }
        if (transfer != null) {
            element.getProperties().remove(replacee);
            element.addToProperty(replacer, (Money) transfer);
        }
    }

    public static void deleteKey(Collection<LoonElement> loonElementen, ContextKey deletee) {
        for (LoonElement element : loonElementen) {
            element.getProperties().remove(deletee);
        }
    }

    public static void copyValues(Collection<LoonElement> loonElementen, ContextKey oldKey, ContextKey newKey) {
        for (LoonElement element : loonElementen) {
            Object checkForConfict = element.getProperty(newKey);
            if (checkForConfict != null) {
                throw new MessageException("Je kan de values van een contextKey niet kopieren als de doel contextKey al gebruikt word");
            }
            Object transfer = element.getProperty(oldKey);
            element.putProperty(newKey, transfer);
        }
    }

