    public static void overnemenVanVorigeBerekening(MoneyKey moneyKey, LoonElementManager manager, Collection<LoonElement> prevElementen) {
        for (LoonElement prevElement : prevElementen) {
            Money prevBedrag = prevElement.getPropertyMoney(moneyKey);
            if (prevBedrag.signum() != 0) {
                Opper prevOpper = prevElement.getOpper();
                Opper opper = RekenTools.findOpper(prevOpper.getOpdracht(), prevOpper.getActualTo());
                AardKodeExtensie looncode = prevElement.getAardKodeExtensie();
                Integer referentieJaar = prevElement.getReferentieJaar();
                LoonElement nieuw = manager.getLoonElement(looncode, opper, referentieJaar);
                if (nieuw == null) {
                    nieuw = new LoonElement(looncode);
                    nieuw.putProperty(AFWIJKEND_REGIME_KEY, prevElement.getPropertyUnchecked(AFWIJKEND_REGIME_KEY));
                    nieuw.setReferentieJaar(referentieJaar);
                    manager.addLoonElement(nieuw, opper);
                }
                nieuw.putProperty(moneyKey, prevBedrag);
            }
        }
    }

    public static void verwijderenVolgensVorigeBerekening(MoneyKey moneyKey, LoonElementManager manager, Collection<LoonElement> prevElementen) {
        for (LoonElement prevElement : prevElementen) {
            Money prevBedrag = prevElement.getPropertyMoney(moneyKey);
            if (prevBedrag.signum() != 0) {
                Opper prevOpper = prevElement.getOpper();
                Opper opper = RekenTools.findOpper(prevOpper.getOpdracht(), prevOpper.getActualTo());
                AardKodeExtensie looncode = prevElement.getAardKodeExtensie();
                Integer referentieJaar = prevElement.getReferentieJaar();
                LoonElement nieuw = manager.getLoonElement(looncode, opper, referentieJaar);
                if (nieuw == null) {
                    nieuw = new LoonElement(looncode);
                    nieuw.putProperty(AFWIJKEND_REGIME_KEY, prevElement.getPropertyUnchecked(AFWIJKEND_REGIME_KEY));
                    nieuw.setReferentieJaar(referentieJaar);
                    manager.addLoonElement(nieuw, opper);
                }
                nieuw.addToProperty(moneyKey, prevBedrag.negate());
            }
        }
    }

